module RefModule (  
    input clk,  
    input rst,  
    input en,  
    output reg [31:0] count  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge rst) begin  
        if (rst)  
            count <= 32'b0;  
        else if (en)  
            count <= count + 1;  
    end  
endmodule
